solutions.python:
import sys
class Solution:
	def __init__(self):
		self.stack = []
		self.empty = True

	def push(self, element):
		if self.empty:
			self.stack.append(element)
			self.empty = False

	def pop(self):
		if not self.empty:
			return self.stack.pop()
		else:
			return -1

n = int(sys.stdin.readline().strip())
s = Solution()
for _ in range(n):
	element = int(sys.stdin.readline().strip())
	s.push(element)
for _ in range(n):
	print(s.pop())

