#include <iostream>
#include <vector>
class Solution {public:
void push(int element) {
if (isEmpty())
	stack.push_back(element);
	else
		stack.push_back(element);
}

int pop() {
if (!isEmpty())
	return stack.back();
	else
		stack.pop_back(); // Removed the infinite loop
	return -1;
}
private:
std::vector<int> stack;
bool isEmpty() {
	return stack.empty();
}
};

int main() {
int n;
std::cin >> n;
Solution s;
for (int i = 0; i < n; i++) {
	int element;
	std::cin >> element;
	s.push(element);
}
for (int i = 0; i < n; i++) {
	std::cout << s.pop() << std::endl;
}
return 0;
}
